import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

import Input from "../../shared/components/FormElements/Input";
import Button from "../../shared/components/FormElements/Button";
import Card from "../../shared/components/UIElements/Card";
import { VALIDATOR_REQUIRE, VALIDATOR_MINLENGTH } from "../../shared/components/util/validators";
import { useForm } from "../../shared/hooks/form-hook"; // Sahi path

import './PlaceForm.css';

const DUMMY_PLACES = [
  {
    id: "p1",
    title: "Dubai – Stad van records en glitter",
    description: "One of the most famous sky scrapers in the world!",
    creator: "u1"
  }
];

const UpdatePlace = () => {
  const placeId = useParams().placeId;

  // Initial empty state setup
  const [formState, inputHandler, setFormData] = useForm({
    title: { value: '', isValid: false },
    description: { value: '', isValid: false }
  }, false);

  const identifiedPlace = DUMMY_PLACES.find(p => p.id === placeId);

  // Jab data mil jaye, tab form update karein
  useEffect(() => {
    if (identifiedPlace) {
      setFormData({
        title: { value: identifiedPlace.title, isValid: true },
        description: { value: identifiedPlace.description, isValid: true }
      }, true);
    }
  }, [setFormData, identifiedPlace]);

  if (!identifiedPlace) {
    return (
      <div className="center">
        <Card><h2>Could not find place!</h2></Card>
      </div>
    );
  }

  // Loading state check
  if (!formState.inputs.title.value) {
    return <div className="center"><h2>Loading...</h2></div>;
  }

  return (
    <form className="place-form">
      <Input 
        id="title" 
        element="input" 
        type="text"
        label="Title"
        validators={[VALIDATOR_REQUIRE()]}
        onInput={inputHandler}
        initialValue={formState.inputs.title.value}
        initialValid={formState.inputs.title.isValid}
      />
      <Input 
        id="description" 
        element="textarea" 
        label="Description"
        validators={[VALIDATOR_MINLENGTH(5)]}
        onInput={inputHandler}
        initialValue={formState.inputs.description.value}
        initialValid={formState.inputs.description.isValid}
      />
      <Button type="submit" disabled={!formState.isValid}>Update PLACE</Button>
    </form>
  );
};

export default UpdatePlace;
